async function init(){try{await api('/api/v1/admin/auth/session');if(page==='products')await products();if(page==='product-form')await editorV3();if(page==='promotions')await promotionsV2();if(page==='partners')await partnersPage();if(page==='banners')await bannersPage();if(page==='themes')await themesPage()}catch(e){if($('#message'))msg(e.message)}}init();

let previewUrls=[];
async function optimizeProductImage(file){
  if(!file.type.startsWith('image/'))throw Error(`${file.name} não é uma imagem válida.`);

  const bitmap=await createImageBitmap(file);
  const maxEdge=1600;
  const scale=Math.min(1,maxEdge/Math.max(bitmap.width,bitmap.height));
  const width=Math.max(1,Math.round(bitmap.width*scale));
  const height=Math.max(1,Math.round(bitmap.height*scale));
  const canvas=document.createElement('canvas');
  canvas.width=width;
  canvas.height=height;
  const context=canvas.getContext('2d',{alpha:true});
  context.imageSmoothingEnabled=true;
  context.imageSmoothingQuality='high';
  context.drawImage(bitmap,0,0,width,height);
  bitmap.close();

  const blob=await new Promise(resolve=>canvas.toBlob(resolve,'image/webp',0.84));
  if(!blob)throw Error(`Não foi possível otimizar ${file.name}.`);
  const baseName=file.name.replace(/\.[^.]+$/,'').replace(/[^a-zA-Z0-9._-]+/g,'-')||'produto';
  return new File([blob],`${baseName}.webp`,{type:'image/webp',lastModified:Date.now()});
}

document.addEventListener('change',async event=>{
  if(event.target.id!=='files')return;
  const input=event.target;
  const upload=document.querySelector('#upload');
  const originalFiles=[...input.files];
  if(upload){upload.disabled=true;upload.textContent='Otimizando imagens...'}

  try{
    const transfer=new DataTransfer();
    for(const file of originalFiles)transfer.items.add(await optimizeProductImage(file));
    input.files=transfer.files;
  }catch(error){
    msg(error.message);
    input.value='';
  }finally{
    if(upload){upload.disabled=false;upload.textContent='Enviar imagens'}
  }

  previewUrls.forEach(URL.revokeObjectURL);previewUrls=[];
  let preview=document.querySelector('#pending-preview');
  if(!preview){preview=document.createElement('div');preview.id='pending-preview';preview.className='media-grid pending-media';event.target.closest('.media-upload')?.after(preview)}
  const hasCurrentCover=Boolean(document.querySelector('.media-card.is-cover'));
  preview.innerHTML=`${hasCurrentCover?'<label class="keep-cover"><input type="radio" name="pending-cover" value="-1" checked> Manter a capa atual</label>':''}${[...input.files].map((file,index)=>{const objectUrl=URL.createObjectURL(file);previewUrls.push(objectUrl);return `<article><div class="preview-image"><img src="${objectUrl}" alt="Preview de ${esc(file.name)}"></div><b>${esc(file.name)}</b><small>WebP otimizada · ${(file.size/1024/1024).toFixed(2)} MB</small><label class="cover-choice"><input type="radio" name="pending-cover" value="${index}" ${!hasCurrentCover&&index===0?'checked':''}> Usar como capa</label></article>`}).join('')}`;
});
